{"nbformat":4,"nbformat_minor":0,"metadata":{"colab":{"provenance":[],"authorship_tag":"ABX9TyMGB8COxYCjMX80OhT9TIgR"},"kernelspec":{"name":"python3","display_name":"Python 3"},"language_info":{"name":"python"}},"cells":[{"cell_type":"code","source":["def bubble_sort(arr):\n","    n = len(arr)\n","    for i in range(n):\n","        swapped = False\n","        for j in range(0, n - i - 1):\n","            if arr[j] > arr[j + 1]:\n","                arr[j], arr[j + 1] = arr[j + 1], arr[j]\n","                swapped = True\n","        if not swapped:\n","            break\n","    return arr\n","\n"],"metadata":{"id":"GQ_T8HcyHH8L","executionInfo":{"status":"ok","timestamp":1778252627403,"user_tz":-420,"elapsed":77,"user":{"displayName":"Nikolas Papua Kiryeman","userId":"03129266034031121217"}}},"execution_count":3,"outputs":[]},{"cell_type":"markdown","source":["procedure bubbleSort(A : list of sortable items)\n","    n := length(A)\n","    repeat\n","        swapped := false\n","        for i := 1 to n-1 inclusive do\n","            if A[i-1] > A[i] then\n","                swap(A[i-1], A[i])\n","                swapped := true\n","        n := n - 1\n","    until not swapped\n","end procedure\n"],"metadata":{"id":"8UgVBS15HcgI"}},{"cell_type":"code","source":["def insertion_sort(arr):\n","    for i in range(1, len(arr)):\n","        key = arr[i]\n","        j = i - 1\n","        while j >= 0 and key < arr[j]:\n","            arr[j + 1] = arr[j]\n","            j -= 1\n","        arr[j + 1] = key\n","    return arr\n"],"metadata":{"id":"gW3QLTI5HgXq","executionInfo":{"status":"ok","timestamp":1778252697530,"user_tz":-420,"elapsed":10,"user":{"displayName":"Nikolas Papua Kiryeman","userId":"03129266034031121217"}}},"execution_count":4,"outputs":[]},{"cell_type":"markdown","source":["procedure selectionSort(A : list of sortable items)\n","    n := length(A)\n","    for i := 0 to n-2 do\n","        minIndex := i\n","        for j := i+1 to n-1 do\n","            if A[j] < A[minIndex] then\n","                minIndex := j\n","        swap(A[i], A[minIndex])\n","end procedure\n"],"metadata":{"id":"lPT68gApHtu6"}},{"cell_type":"code","source":["def insertion_sort(arr):\n","    for i in range(1, len(arr)):\n","        key = arr[i]\n","        j = i - 1\n","        while j >= 0 and key < arr[j]:\n","            arr[j + 1] = arr[j]\n","            j -= 1\n","        arr[j + 1] = key\n","    return arr\n"],"metadata":{"id":"FuAI1kO5H3Du","executionInfo":{"status":"ok","timestamp":1778252776283,"user_tz":-420,"elapsed":55,"user":{"displayName":"Nikolas Papua Kiryeman","userId":"03129266034031121217"}}},"execution_count":5,"outputs":[]},{"cell_type":"markdown","source":["procedure insertionSort(A : list of sortable items)\n","    for i := 1 to length(A)-1 do\n","        key := A[i]\n","        j := i - 1\n","        while j >= 0 and A[j] > key do\n","            A[j + 1] := A[j]\n","            j := j - 1\n","        A[j + 1] := key\n","end procedure\n"],"metadata":{"id":"z1OGtqPpIA89"}},{"cell_type":"code","source":["def quick_sort(arr):\n","    if len(arr) <= 1:\n","        return arr\n","    pivot = arr[len(arr) // 2]\n","    left = [x for x in arr if x < pivot]\n","    middle = [x for x in arr if x == pivot]\n","    right = [x for x in arr if x > pivot]\n","    return quick_sort(left) + middle + quick_sort(right)\n"],"metadata":{"id":"ClQkkV_ZIFNP","executionInfo":{"status":"ok","timestamp":1778252821862,"user_tz":-420,"elapsed":61,"user":{"displayName":"Nikolas Papua Kiryeman","userId":"03129266034031121217"}}},"execution_count":6,"outputs":[]},{"cell_type":"markdown","source":["procedure quickSort(A, low, high)\n","    if low < high then\n","        p := partition(A, low, high)\n","        quickSort(A, low, p - 1)\n","        quickSort(A, p + 1, high)\n","\n","procedure partition(A, low, high)\n","    pivot := A[high]\n","    i := low - 1\n","    for j := low to high - 1 do\n","        if A[j] < pivot then\n","            i := i + 1\n","            swap(A[i], A[j])\n","    swap(A[i + 1], A[high])\n","    return i + 1\n"],"metadata":{"id":"NknZjyMgIME9"}}]}